USE nyctaxi_db;

CREATE MASTER KEY ENCRYPTION BY PASSWORD = 'NycTaxi@Master2024!';

CREATE EXTERNAL DATA SOURCE bronze_source
WITH (
    LOCATION = 'https://adlsnyctaxide.dfs.core.windows.net/bronze'
);

CREATE EXTERNAL DATA SOURCE silver_source
WITH (
    LOCATION = 'https://adlsnyctaxide.dfs.core.windows.net/silver'
);

CREATE EXTERNAL FILE FORMAT parquet_format
WITH (FORMAT_TYPE = PARQUET);


USE nyctaxi_db;

-- Create external table for taxi zone reference data
-- Source file lives in bronze/reference/taxi_zone_lookup.csv
CREATE EXTERNAL FILE FORMAT csv_format
WITH (
    FORMAT_TYPE = DELIMITEDTEXT,
    FORMAT_OPTIONS (
        FIELD_TERMINATOR = ',',
        STRING_DELIMITER = '"',
        FIRST_ROW = 2,        -- skip header row
        USE_TYPE_DEFAULT = TRUE
    )
);

CREATE EXTERNAL TABLE dbo.taxi_zone_lookup (
    LocationID    INT,
    Borough       VARCHAR(50),
    Zone          VARCHAR(100),
    service_zone  VARCHAR(50)
)
WITH (
    LOCATION     = 'reference/taxi_zone_lookup.csv',
    DATA_SOURCE  = bronze_source,
    FILE_FORMAT  = csv_format
);

-- Verify it worked
SELECT TOP 5 * FROM dbo.taxi_zone_lookup;
